package com.hospital.management.model;/** String-bound room form. */public class RoomForm{private Long roomId,departmentId;private String roomNumber,roomType,floorNumber,dailyRate,status;public Long getRoomId(){return roomId;}public void setRoomId(Long v){roomId=v;}public String getRoomNumber(){return roomNumber;}public void setRoomNumber(String v){roomNumber=v;}public String getRoomType(){return roomType;}public void setRoomType(String v){roomType=v;}public String getFloorNumber(){return floorNumber;}public void setFloorNumber(String v){floorNumber=v;}public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public String getDailyRate(){return dailyRate;}public void setDailyRate(String v){dailyRate=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}}
